import pytest
import torch

from . import base

# Hardcoded shapes: affine_grid_generator requires (N,2,3) theta + [N,C,H,W] size;
# CI --level core overrides GenericBenchmark shapes with 1D/3D defaults,
# so we use a custom Benchmark subclass with set_shapes override.
AFFINE_GRID_SHAPES = [
    (1, 4, 4),
    (1, 8, 8),
    (2, 8, 8),
    (4, 16, 16),
]


class AffineGridBenchmark(base.Benchmark):
    def set_shapes(self, shape_file_path=None):
        self.shapes = AFFINE_GRID_SHAPES

    def get_input_iter(self, cur_dtype):
        for shape in self.shapes:
            N, H, W = shape
            theta = torch.randn((N, 2, 3), dtype=cur_dtype, device=self.device)
            size = [N, 3, H, W]
            align_corners = False
            yield theta, size, align_corners


@pytest.mark.affine_grid_generator
def test_affine_grid_generator():
    bench = AffineGridBenchmark(
        op_name="affine_grid_generator",
        torch_op=torch.affine_grid_generator,
        # affine_grid kernel uses float32 internally; Half precision causes mismatch
        dtypes=[torch.float32],
    )
    bench.run()
